/* Mobile */
@media (max-width: 768px) {
  :root {
    --container-max: 100%;
    --container-padding: 1rem;
    --header-height: 64px;
  }

  h1 { font-size: var(--font-size-2xl); }
  h2 { font-size: var(--font-size-xl); }
  h3 { font-size: var(--font-size-lg); }

  .section {
    padding: var(--spacing-2xl) 0;
  }

  .section-header {
    flex-direction: column;
    align-items: flex-start;
  }

  /* Mobile Navigation */
  .nav-links {
    display: none;
  }

  .hamburger {
    display: flex;
  }

  body.nav-open {
    overflow: hidden;
  }

  /* Hero Mobile */
  .hero {
    padding-top: var(--header-height);
  }

  .hero-content {
    padding: var(--spacing-lg);
  }

  .hero-title {
    font-size: 2rem;
  }

  .hero-subtitle {
    font-size: var(--font-size-base);
  }

  .hero-ctas {
    flex-direction: column;
    width: 100%;
  }

  .hero-ctas .btn {
    width: 100%;
  }

  /* Grids Mobile */
  .news-grid,
  .drug-grid,
  .events-grid,
  .courses-grid {
    grid-template-columns: 1fr;
  }

  /* Database Search Mobile */
  .database-search {
    flex-direction: column;
  }

  .database-search input,
  .database-search select {
    width: 100%;
  }

  /* Footer Mobile */
  .footer-grid {
    grid-template-columns: 1fr;
    gap: var(--spacing-xl);
  }

  .newsletter-form {
    flex-direction: column;
  }

  .newsletter-form .btn {
    width: 100%;
  }
}

/* Reduced Motion */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  html {
    scroll-behavior: auto;
  }
}

/* Wide Screens */
@media (min-width: 1440px) {
  :root {
    --container-max: 1320px;
  }

  .hero-title {
    font-size: 3.5rem;
  }
}

/**
 * ParamedicHub - Main JavaScript
 * Handles smooth scroll, mobile navigation, search filter, and animations
 */

document.addEventListener('DOMContentLoaded', function() {
  // Initialize all modules
  initSmoothScroll();
  initMobileNav();
  initHeaderScroll();
  initScrollAnimations();
  initDatabaseSearch();
});

/**
 * Smooth Scroll Navigation
 * Handles anchor links with smooth scrolling
Scroll() {
  */
function initSmooth document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
      const href = this.getAttribute('href');

      // Skip if it's just "#"
      if (href === '#') return;

      e.preventDefault();
      const target = document.querySelector(href);

      if (target) {
        const headerOffset = 72;
        const elementPosition = target.getBoundingClientRect().top;
        const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

        window.scrollTo({
          top: offsetPosition,
          behavior: 'smooth'
        });

        // Close mobile nav if open
        closeMobileNav();
      }
    });
  });
}

/**
 * Mobile Navigation
 * Handles hamburger menu and drawer
 */
function initMobileNav() {
  const hamburger = document.querySelector('.hamburger');
  const mobileNav = document.querySelector('.mobile-nav');
  const overlay = document.querySelector('.mobile-nav__overlay');
  const closeBtn = document.querySelector('.mobile-nav__close');

  if (!hamburger || !mobileNav || !overlay) return;

  hamburger.addEventListener('click', openMobileNav);
  closeBtn?.addEventListener('click', closeMobileNav);
  overlay.addEventListener('click', closeMobileNav);

  // Close on escape key
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeMobileNav();
  });

  function openMobileNav() {
    hamburger.classList.add('active');
    mobileNav.classList.add('open');
    overlay.classList.add('active');
    document.body.style.overflow = 'hidden';
  }

  function closeMobileNav() {
    hamburger.classList.remove('active');
    mobileNav.classList.remove('open');
    overlay.classList.remove('active');
    document.body.style.overflow = '';
  }

  // Make closeMobileNav available globally for smooth scroll
  window.closeMobileNav = closeMobileNav;
}

/**
 * Header Scroll Effect
 * Adds shadow when scrolling past hero
 */
function initHeaderScroll() {
  const header = document.querySelector('.site-header');
  if (!header) return;

  let lastScroll = 0;

  window.addEventListener('scroll', throttle(() => {
    const currentScroll = window.pageYOffset;

    if (currentScroll > 100) {
      header.classList.add('scrolled');
    } else {
      header.classList.remove('scrolled');
    }

    lastScroll = currentScroll;
  }, 100));
}

/**
 * Throttle function
 * Limits function execution rate
 */
function throttle(func, limit) {
  let inThrottle;
  return function() {
    if (!inThrottle) {
      func.apply(this, arguments);
      inThrottle = true;
      setTimeout(() => inThrottle = false, limit);
    }
  };
}

/**
 * Scroll-triggered Animations
 * Uses Intersection Observer for fade-up effects
 */
function initScrollAnimations() {
  const animatedElements = document.querySelectorAll('.fade-up');

  if (!animatedElements.length) return;

  const observerOptions = {
    root: null,
    rootMargin: '0px',
    threshold: 0.1
  };

  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('animated');
        observer.unobserve(entry.target);
      }
    });
  }, observerOptions);

  animatedElements.forEach(el => {
    observer.observe(el);
  });
}

/**
 * Database Search Filter
 * Filters drug cards based on search input
 */
function initDatabaseSearch() {
  const searchInput = document.querySelector('.database-search input');
  const categorySelect = document.querySelector('.database-search select');
  const drugCards = document.querySelectorAll('.drug-card');

  if (!searchInput || !drugCards.length) return;

  function filterCards() {
    const query = searchInput.value.toLowerCase().trim();
    const category = categorySelect?.value || 'all';

    // Show all if query is empty
    if (query.length === 0) {
      drugCards.forEach(card => {
        card.style.display = '';
      });
      return;
    }

    // Minimum 2 characters to search
    if (query.length < 2) return;

    drugCards.forEach(card => {
      const text = card.textContent.toLowerCase();
      const matchesSearch = text.includes(query);

      // For now, show all categories
      const matchesCategory = category === 'all' || category === 'All Categories';

      if (matchesSearch && matchesCategory) {
        card.style.display = '';
      } else {
        card.style.display = 'none';
      }
    });
  }

  // Debounce search input
  let debounce;
  searchInput.addEventListener('input', () => {
    clearTimeout(debounce);
    debounce = setTimeout(filterCards, 300);
  });

  // Filter on category change
  categorySelect?.addEventListener('change', filterCards);
}

/**
 * Newsletter Form Handler
 * Handles form submission with loading state
 */
function initNewsletterForm() {
  const form = document.querySelector('.newsletter-form');
  if (!form) return;

  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const email = form.querySelector('input[type="email"]');
    const button = form.querySelector('button');

    if (!email?.value) return;

    // Basic email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email.value)) {
      showMessage(form, 'error', 'Please enter a valid email address');
      return;
    }

    // Show loading state
    button.classList.add('loading');
    button.disabled = true;

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000));

      showMessage(form, 'success', 'Thanks for subscribing!');
      form.reset();
    } catch (error) {
      showMessage(form, 'error', 'Something went wrong. Please try again.');
    } finally {
      button.classList.remove('loading');
      button.disabled = false;
    }
  });

  function showMessage(form, type, text) {
    // Remove existing message
    const existing = form.querySelector('.form-message');
    if (existing) existing.remove();

    const message = document.createElement('div');
    message.className = `form-message form-message--${type}`;
    message.textContent = text;
    form.appendChild(message);

    if (type === 'success') {
      setTimeout(() => message.remove(), 5000);
    }
  }
}

// Initialize newsletter form
initNewsletterForm();

